insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:2-1-values-promoted-through-sport:learn:1473c755', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'learn', 'mcq', 1, '{"readingTitle": "Naming a value isn''t enough — the exam skill", "reading": "<h4>Naming is only the start</h4>\n<ul>\n<li>Weak answer: <em>\"A value sport promotes is fair play.\"</em> That names a value but shows no understanding.</li>\n<li>Strong answer: <em>\"Fair play is a value sport can promote — for example, a player telling the referee the ball crossed the line for a throw-in, even though the decision had gone their way.\"</em></li>\n<li>The mark almost always rewards <strong>linking the value to a real sporting example</strong>, not the name on its own.</li>\n</ul>\n<h4>Build every answer the same way</h4>\n<ul>\n<li><strong>Value → sporting example → what it shows.</strong> State the value, describe a moment in sport, then explain why that moment demonstrates the value.</li>\n<li>In a Section B scenario, use a detail <strong>from that scenario</strong> as your example rather than a general one you already had prepared.</li>\n</ul>", "question": "A question asks you to explain how sport can promote one named value. What is most likely to earn the marks?", "options": ["Naming the value and giving a sporting example that shows it happening", "Writing the value''s name clearly, underlined, in capital letters for emphasis", "Listing as many of the seven values as you can remember", "Describing your own favourite sporting fixture in detail"]}'::jsonb, '{"answer": 0, "explain": "Explain questions on this topic reward the value plus a sporting example that shows it — naming the value alone, or listing every value, earns little."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:misc:08b4005d', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Tolerance and respect are two separate values, so I can list them separately to pick up two marks.</p><p><strong>✅ The correct idea:</strong> They are always marked as ONE combined value. Writing ''tolerance'' and ''respect'' as two different values on an ''identify two values'' question does not earn two marks — it usually earns one at most, because the examiner sees it as the same value written twice.</p>", "question": "On an ''identify two values'' question, writing ''tolerance'' then ''respect'' as your two answers usually earns...", "options": ["Two marks, because they are two separate values in the specification", "One mark at most, because they are one combined value written twice", "Zero marks, because neither word appears in the specification at all", "Bonus marks for extra detail beyond what was asked"]}'::jsonb, '{"answer": 1, "explain": "Tolerance and respect count as one value, so giving both words as your ''two'' values usually earns only one mark, not two."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:misc:c5e5c95a', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> National pride is basically the same idea as citizenship, because both are about people coming together.</p><p><strong>✅ The correct idea:</strong> They are different ideas the exam keeps side by side. National pride is about supporting a national TEAM, creating a shared identity across the whole country. Citizenship is about building links within a LOCAL community, such as through a club. A question can ask about either, so keep the scale (national vs local) clear.</p>", "question": "What is the key difference between national pride and citizenship?", "options": ["There is no real difference at all — the two ideas mean exactly the same thing, always", "National pride is about a national team; citizenship is about local community links", "Citizenship only applies to professional athletes, never to amateurs", "National pride can only be shown by people who play for their country"]}'::jsonb, '{"answer": 1, "explain": "National pride works at a national scale (supporting the national team); citizenship works at a local scale (community links through sport)."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:misc:527285f9', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Naming a value like ''fair play'' is enough to get the mark on its own.</p><p><strong>✅ The correct idea:</strong> Naming is only the first step. The mark scheme rewards linking the value to a sporting example that actually shows it happening. Weak answer: \"Fair play.\" Full-marks answer: \"Fair play — a player tells the referee the ball crossed the line even though the decision had gone their way.\"</p>", "question": "A question asks you to explain how sport promotes one value. What is needed for full marks?", "options": ["The value''s name only, written out clearly and neatly on the line", "The value''s name PLUS a sporting example that shows it", "A list of every value you can remember", "A description of your own favourite team"]}'::jsonb, '{"answer": 1, "explain": "Full marks need the value named and a sporting example linked to it — the name alone does not show understanding."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:misc:3b92f3b2', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Excellence just means winning every match or competition you take part in.</p><p><strong>✅ The correct idea:</strong> Excellence means striving to be your best and giving maximum effort, whether or not you actually win. An athlete who trains hard and improves their personal best is showing excellence even in a competition they lose.</p>", "question": "Which of these best shows the value of excellence?", "options": ["An athlete who wins a competition very easily without ever trying that hard at all", "An athlete who trains hard and improves their personal best, even after losing", "A team that refuses to shake hands with the opposition after a narrow defeat", "A crowd that boos the away team throughout an entire match"]}'::jsonb, '{"answer": 1, "explain": "Excellence is about maximum effort and self-improvement, not the result — the athlete who improves their best time shows it even in defeat."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tips:2a02f25a', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Values questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two values sport can promote\" = write two value names, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what the value looks like in practice, without needing a full reason.</li>\n<li><strong>Explain</strong> — give a sporting example and link it to the value. \"Explain how sport can promote fair play\" = name fair play, then give an example that shows it.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed with an example; [4] in Section B wants points applied to the given scenario.</p>", "question": "A question says: ''Identify two values sport can promote [2]''. What is the safest answer?", "options": ["A long paragraph describing one value in detail", "Two value names, nothing more", "One value name with a full sporting example attached", "A list of six or seven different values"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one value in depth, or listing extra values, wastes time without extra credit."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tips:310c5b11', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: value AND a sporting example", "reading": "<p>The single most common way to lose marks here is stopping at the value''s name. Build every answer as <strong>value → sporting example → what it shows</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Fair play.\"</li>\n<li><strong>✅ full marks:</strong> \"Fair play — a player tells the referee the ball crossed the line even though the decision had gone in their favour.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named event, club or person). Then you must use a detail <em>from that scenario</em> as your example, not one you already had prepared.</p>", "question": "In a Section B scenario question about a named event, your sporting example should come from...", "options": ["absolutely any sport you happen to like", "the scenario you are given", "a famous athlete not mentioned in the scenario", "your own school sports day only"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you, not a prepared general example."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tips:d885362b', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where values appear + sentence starters", "reading": "<p><strong>Where it shows up:</strong> values appear as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about a club or event, and feed <strong>Section C</strong> 8-mark answers about how far sport really promotes positive values.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the seven values in threes — team spirit/fair play/citizenship, then tolerance & respect/inclusion, then national pride/excellence — so you can always recall a few.</li>\n<li>For every value, memorise <em>one</em> ready-made sporting example — that example is usually where the mark is.</li>\n<li>Never split tolerance and respect into two values — it is one, and treating it as two costs marks rather than gaining them.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way sport promotes positive values is… because…\"</li>\n<li>\"This matters because it shows…\"</li>\n<li>\"On the other hand, this value might not always be shown, because…\"</li>\n</ul>", "question": "Why is it risky to write ''tolerance'' and ''respect'' as two separate answers on an ''identify'' question?", "options": ["It is not risky at all, and it always earns full marks either way, every time", "They are one combined value, so it usually earns only one mark, not two", "The examiner will refuse to mark the question at all", "It means you cannot use either word anywhere else in the exam"]}'::jsonb, '{"answer": 1, "explain": "Because tolerance and respect are one combined value, giving both words as separate answers usually earns only one mark rather than two."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:fib:c6ff77db', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'fib', 'fib', 1, '{"question": "Team _____ means supporting and encouraging your teammates as you work together toward a shared goal.", "blankOptions": {"B1": ["spirit", "cheat", "effort", "community"]}}'::jsonb, '{"blanks": {"B1": "spirit"}}'::jsonb),
