('sport-studies:2-1-values-promoted-through-sport:fib:222928cc', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'fib', 'fib', 1, '{"question": "Inclusion means giving people from every social group an equal _____ to take part.", "blankOptions": {"B1": ["community", "cultures", "effort", "opportunity"]}}'::jsonb, '{"blanks": {"B1": "opportunity"}}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:fib:d7d38c74', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'fib', 'fib', 1, '{"question": "Excellence means striving to be your best by giving maximum _____.", "blankOptions": {"B1": ["opportunity", "spirit", "effort", "cultures"]}}'::jsonb, '{"blanks": {"B1": "effort"}}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:match:c54c3be1', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Team spirit”?", "options": ["A greater understanding and appreciation of people from other cultures, gained through sport", "Supporting and encouraging teammates as everyone works together toward a shared goal", "Following the rules honestly, never cheating, and accepting the decisions officials make", "Giving people from every social group an equal opportunity to take part in sport"]}'::jsonb, '{"answer": 1, "explain": "“Team spirit” means: Supporting and encouraging teammates as everyone works together toward a shared goal"}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:match:ee5dc690', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fair play”?", "options": ["Supporting and encouraging teammates as everyone works together toward a shared goal", "Following the rules honestly, never cheating, and accepting the decisions officials make", "Striving to be your best by giving maximum effort and always trying to improve", "Giving people from every social group an equal opportunity to take part in sport"]}'::jsonb, '{"answer": 1, "explain": "“Fair play” means: Following the rules honestly, never cheating, and accepting the decisions officials make"}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:match:ab778e82', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Citizenship”?", "options": ["Supporting and encouraging teammates as everyone works together toward a shared goal", "A greater understanding and appreciation of people from other cultures, gained through sport", "Using sport to build positive links and connections within the local community", "Following the rules honestly, never cheating, and accepting the decisions officials make"]}'::jsonb, '{"answer": 2, "explain": "“Citizenship” means: Using sport to build positive links and connections within the local community"}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:match:7c5c1a26', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Tolerance and respect”?", "options": ["Supporting a national team in a way that creates a shared sense of identity and unity", "A greater understanding and appreciation of people from other cultures, gained through sport", "Using sport to build positive links and connections within the local community", "Striving to be your best by giving maximum effort and always trying to improve"]}'::jsonb, '{"answer": 1, "explain": "“Tolerance and respect” means: A greater understanding and appreciation of people from other cultures, gained through sport"}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:match:6d15a7af', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Inclusion”?", "options": ["Following the rules honestly, never cheating, and accepting the decisions officials make", "Giving people from every social group an equal opportunity to take part in sport", "Striving to be your best by giving maximum effort and always trying to improve", "A greater understanding and appreciation of people from other cultures, gained through sport"]}'::jsonb, '{"answer": 1, "explain": "“Inclusion” means: Giving people from every social group an equal opportunity to take part in sport"}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:match:d168641e', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National pride”?", "options": ["Supporting a national team in a way that creates a shared sense of identity and unity", "Using sport to build positive links and connections within the local community", "Striving to be your best by giving maximum effort and always trying to improve", "Giving people from every social group an equal opportunity to take part in sport"]}'::jsonb, '{"answer": 0, "explain": "“National pride” means: Supporting a national team in a way that creates a shared sense of identity and unity"}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:match:f4b6ca97', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Excellence”?", "options": ["Following the rules honestly, never cheating, and accepting the decisions officials make", "A greater understanding and appreciation of people from other cultures, gained through sport", "Giving people from every social group an equal opportunity to take part in sport", "Striving to be your best by giving maximum effort and always trying to improve"]}'::jsonb, '{"answer": 3, "explain": "“Excellence” means: Striving to be your best by giving maximum effort and always trying to improve"}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:exam:f92c5abe', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is one of the three Olympic values?", "options": ["Courage", "Friendship", "Inspiration", "Equality"], "hint": "Remember: the Olympic values are Excellence, Friendship and Respect — the other three names belong to the Paralympic list.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1)</h5>\n<p><strong>Answer: B — Friendship.</strong></p>\n<ul>\n<li>Friendship is one of the three Olympic values (with Excellence and Respect).</li>\n<li>Courage, Inspiration and Equality are Paralympic values, not Olympic values.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:mcq:a56bd49b', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'mcq', 'mcq', 1, '{"question": "A student says the Olympic Creed means ''you don''t need to try, just turn up.'' What is wrong with this understanding?", "options": ["Nothing is wrong — turning up without trying is exactly what the Creed asks of every athlete taking part", "The Creed actually asks for an honest, maximum effort during the competition itself, not just attendance", "The Creed is only about winning medals, so how hard an athlete tries does not matter at all", "The Creed has nothing to do with how much effort an athlete puts in once the competition starts"]}'::jsonb, '{"answer": 1, "explain": "The Creed is about giving an honest, maximum effort in the event itself — not about attendance alone, and not that effort is irrelevant."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:mcq:529af42c', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'mcq', 'mcq', 1, '{"question": "Why are the five Olympic rings drawn interlocking rather than as five separate shapes?", "options": ["To show the continents connecting and coming together through sport", "To show that each continent must compete completely separately from every other continent", "To make the symbol easier to print in a single colour on flags and posters", "To represent five different events that always take place at every single Games"]}'::jsonb, '{"answer": 0, "explain": "Interlocking rings show connection and unity between the continents. They are not about printing convenience, separation, or a fixed set of events."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:mcq:e9698c09', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'mcq', 'mcq', 1, '{"question": "''Inspiration'' as an official sporting value is most closely associated with which movement?", "options": ["The Olympic Movement only, and never the Paralympic Movement", "The Paralympic Movement", "Neither movement — inspiration is not an official value of either one", "Only one-off events that have no connection to the Olympic or Paralympic Games"]}'::jsonb, '{"answer": 1, "explain": "Inspiration is one of the four Paralympic values (with Courage, Determination and Equality) — it is not one of the three Olympic values."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:mcq:fad75004', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'mcq', 'mcq', 1, '{"question": "A performer trains hard to beat their own personal best time, even though they already know they will not win a medal this time. Which Olympic value does this best show?", "options": ["Excellence — striving to reach your personal best, not only aiming to beat other people", "Friendship — building relationships with competitors from other countries and backgrounds", "Equality — making sure every competitor is given the same fair opportunity to take part", "Courage — finding the mental strength needed to perform well under real pressure"]}'::jsonb, '{"answer": 0, "explain": "Chasing your own personal best, regardless of the medal outcome, is Excellence. Friendship is about relationships, Equality about fair opportunity, and Courage is a Paralympic value, not Olympic."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:mcq:f0cad655', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'mcq', 'mcq', 1, '{"question": "Two competitors shake hands and congratulate one another after a hard-fought, fairly contested race. Which Olympic value does this best demonstrate?", "options": ["Friendship — the bonds and understanding that competing together can build between people", "Respect — for the rules, for each other, and for the spirit of fair competition", "Determination — refusing to give up despite the real difficulty of the challenge faced", "Inspiration — using a performance to motivate and change how other people think"]}'::jsonb, '{"answer": 1, "explain": "Fair, gracious behaviour toward an opponent after a clean contest is Respect. Friendship is about wider bonds, and Determination/Inspiration are Paralympic values, not Olympic."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:mcq:29a298d5', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'mcq', 'mcq', 1, '{"question": "An athlete recovering from a serious injury refuses to give up on training and eventually competes again. Which Paralympic value does this best show?", "options": ["Equality — showing that every competitor deserves the same fair chance to take part", "Excellence — striving to reach the highest personal standard that you possibly can", "Determination — refusing to give up despite setbacks, and pushing on toward a goal", "Respect — following the rules and treating opponents and officials fairly"]}'::jsonb, '{"answer": 2, "explain": "Pushing through setbacks without giving up is Determination. Equality is about fair opportunity, Excellence is an Olympic value, and Respect is about fair play, not perseverance."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tf:f1300382', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tf', 'tf', 1, '{"question": "The Olympic Creed teaches that honest, maximum effort matters as much as the final result."}'::jsonb, '{"answer": true, "explain": "That is the core idea — genuine sporting success comes from the honesty of your effort, not only from whether you win."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tf:5d6dd033', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tf', 'tf', 1, '{"question": "The five Olympic rings represent five specific nations that are the only countries ever allowed to host the Games."}'::jsonb, '{"answer": false, "explain": "The rings represent the coming together of the five continents through sport — they are not a fixed list of host nations."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tf:5ec28e4a', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tf', 'tf', 1, '{"question": "Excellence, Friendship and Respect are the three Olympic values."}'::jsonb, '{"answer": true, "explain": "Correct — these three values belong to the Olympic Games specifically."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tf:d3ed5877', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tf', 'tf', 1, '{"question": "Courage, Determination, Inspiration and Equality are the four Olympic values."}'::jsonb, '{"answer": false, "explain": "These four are the Paralympic values, not the Olympic values. Mixing the two sets up is a very common mistake."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tf:688d6161', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tf', 'tf', 1, '{"question": "Determination is a Paralympic value about refusing to give up despite setbacks."}'::jsonb, '{"answer": true, "explain": "Correct — Determination is about pushing on toward a goal even when things go wrong."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tf:26c2aef7', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tf', 'tf', 1, '{"question": "The Olympic Creed means an athlete never needs to try hard once the competition begins."}'::jsonb, '{"answer": false, "explain": "The opposite is true — the Creed is specifically about giving an honest, maximum effort during the competition."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:learn:e269b279', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'learn', 'mcq', 1, '{"readingTitle": "The Olympic Creed — the idea behind it", "reading": "<h4>What the Creed is</h4>\n<ul>\n<li>The <strong>Olympic Creed</strong> is a short statement of the philosophy behind Olympic competition — it sums up what the Games are really meant to be about.</li>\n<li>Its core idea, in plain terms: genuine sporting achievement comes from the honesty of your effort and the personal challenge of competing at your very best — not simply from whether you walk away with a medal.</li>\n</ul>\n<h4>Why this trips people up</h4>\n<ul>\n<li>Some students read this and think it means \"trying doesn''t matter, just show up.\" That is the <strong>opposite</strong> of the idea — the Creed is about giving a maximum, honest effort in the contest itself, whatever the final result turns out to be.</li>\n<li>An athlete who competes flat-out and finishes eighth has lived out the Creed far more than one who wins by cheating or by barely trying at all.</li>\n<li>Exam answers that just say \"it means taking part\" without mentioning honest effort or personal best usually miss the real point the mark scheme is after.</li>\n</ul>", "question": "Which of these best captures the idea behind the Olympic Creed?", "options": ["The Creed says that simply turning up to the stadium is enough, and no real effort is required once the event actually begins at all", "The Creed says that only athletes who win a medal have achieved anything worth celebrating at the Games", "The Creed says that genuine sporting success comes from an honest, maximum effort in competing, not only from winning", "The Creed says that athletes should beat their rivals by whatever method proves necessary to win"]}'::jsonb, '{"answer": 2, "explain": "The Creed is about honest, maximum effort in the competition itself — not about turning up without trying, not about medals alone, and not about winning by any means necessary."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:learn:fc38ba0b', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'learn', 'mcq', 1, '{"readingTitle": "The Olympic symbol — the five rings", "reading": "<h4>What the symbol shows</h4>\n<ul>\n<li>The Olympic symbol is <strong>five interlocking rings</strong>.</li>\n<li>The rings represent the <strong>coming together of the five continents of the world through sport</strong> — the whole point is unity, athletes from every part of the globe meeting in one competition.</li>\n</ul>\n<h4>The trap to avoid</h4>\n<ul>\n<li>A common mistake is assuming each ring is permanently \"assigned\" to one specific continent by its colour, as if it were a fixed key. The exam-relevant idea is simpler and more important: the rings are <strong>interlocking</strong> (linked, not separate) to show connection and unity, not a strict colour-to-continent code.</li>\n<li>If a question asks what the rings represent, the safe, testable answer is \"the coming together of the five continents through sport\" — not a list of which colour belongs to which continent.</li>\n</ul>", "question": "What do the five interlocking rings on the Olympic symbol represent?", "options": ["The coming together of the five continents of the world through sport", "Five colours that are each permanently fixed to one particular continent", "Five nations that are the only countries ever allowed to host the Games", "Five separate sports that must always feature at every single Olympic Games"]}'::jsonb, '{"answer": 0, "explain": "The rings symbolise unity — the five continents coming together through sport. They are not a fixed colour-to-continent code, a list of host nations, or a list of sports."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:learn:17ed16e5', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'learn', 'mcq', 1, '{"readingTitle": "The Olympic values: Excellence, Friendship, Respect", "reading": "<h4>The three Olympic values</h4>\n<ul>\n<li><strong>Excellence</strong> — striving to give your very best performance and to keep improving, measured against your own personal standard as well as against other competitors.</li>\n<li><strong>Friendship</strong> — the relationships, understanding and connections that competing together can build between people from different countries and backgrounds.</li>\n<li><strong>Respect</strong> — fair play, and consideration for the rules, for your opponents, for officials, and for yourself (including competing without banned substances).</li>\n</ul>\n<h4>How to use them in an answer</h4>\n<ul>\n<li>Don''t just name the value — link it to a behaviour. \"Excellence\" on its own earns little; \"Excellence, because the athlete kept improving their own personal best time\" shows real understanding.</li>\n<li>These three values belong to the <strong>Olympic</strong> Games specifically — keep them separate in your memory from the Paralympic set below.</li>\n</ul>", "question": "Which three values are the Olympic values?", "options": ["Excellence, Friendship and Respect", "Courage, Determination and Inspiration", "Speed, Power and Endurance", "Excellence, Determination and Equality"]}'::jsonb, '{"answer": 0, "explain": "The three Olympic values are Excellence, Friendship and Respect. The other options either mix in Paralympic values or use words that aren''t official values at all."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:learn:0c2a1ade', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'learn', 'mcq', 1, '{"readingTitle": "The Paralympic values: Courage, Determination, Inspiration, Equality", "reading": "<h4>The four Paralympic values</h4>\n<ul>\n<li><strong>Courage</strong> — the mental strength to face a real challenge and perform under pressure, even when the odds feel stacked against you.</li>\n<li><strong>Determination</strong> — refusing to give up despite setbacks, and pushing on to reach your full potential.</li>\n<li><strong>Inspiration</strong> — using your performance to motivate other people and change how they see what is possible.</li>\n<li><strong>Equality</strong> — showing that every competitor deserves the same fair opportunity to take part and to be recognised on equal terms, whatever their impairment.</li>\n</ul>\n<h4>The #1 trap the exam tests</h4>\n<ul>\n<li>Students very often mix up which set a value belongs to — for example, writing \"Courage\" as an Olympic value, or \"Excellence\" as a Paralympic value. They are two separate, named lists: <strong>Olympic</strong> = Excellence/Friendship/Respect; <strong>Paralympic</strong> = Courage/Determination/Inspiration/Equality.</li>\n<li>\"Equality\" here is broader than just fairness after the event — it is about equal opportunity to compete and be valued as an athlete in the first place.</li>\n</ul>", "question": "Which four values are the Paralympic values?", "options": ["The four Paralympic values are Courage, Determination, Inspiration and Equality", "The four Paralympic values are Excellence, Friendship, Respect and Equality", "The four Paralympic values are Strength, Speed, Power and Precision", "The four Paralympic values are Determination, Excellence, Respect and Courage, in that order"]}'::jsonb, '{"answer": 0, "explain": "The four Paralympic values are Courage, Determination, Inspiration and Equality. The other options either borrow Olympic values or use words that aren''t the official set."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:misc:d98f26ea', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often think the Olympic Creed means trying doesn''t matter, as long as you show up.</p><p><strong>✅ The correct idea:</strong> It means the opposite. The Creed is about giving an honest, maximum effort in the contest itself — the taking part has to involve genuinely trying your best, not just being present. An athlete who competes flat-out and finishes last has lived out the idea far more than one who barely tries.</p>", "question": "What is wrong with saying the Olympic Creed means ''just show up, effort doesn''t matter''?", "options": ["Nothing is wrong — that is exactly what the Creed asks of every competitor, regardless of effort, at all", "The Creed actually requires an honest, maximum effort during the event itself, not just attendance", "The Creed only ever applies to athletes who go on to win an official medal", "The Creed was written specifically to discourage athletes from trying their hardest"]}'::jsonb, '{"answer": 1, "explain": "The Creed asks for genuine, maximum effort in the competition — attendance alone, without trying, is not what the idea describes."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:misc:028ac667', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Some students think each of the five Olympic rings is permanently tied to one single, fixed continent by its colour.</p><p><strong>✅ The correct idea:</strong> The exam-relevant idea is unity, not a colour key. The rings are drawn interlocking specifically to show the continents connecting and coming together through sport — that is the point being tested, not a strict one-ring-one-continent colour code.</p>", "question": "What is the exam-relevant point about the five interlocking Olympic rings?", "options": ["Each ring''s colour is permanently and officially fixed to one single specific continent", "The rings show the continents connecting and coming together through sport", "The rings represent five completely different sports played at every single Games", "The rings show exactly which nations are allowed to host only the Winter Games"]}'::jsonb, '{"answer": 1, "explain": "The tested idea is unity — the continents coming together — not a colour-to-continent lookup table, a list of sports, or host nations."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:misc:127fb4fe', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A very common mistake is mixing up which values belong to the Olympics and which belong to the Paralympics — for example, saying ''Courage'' is an Olympic value.</p><p><strong>✅ The correct idea:</strong> Keep the two lists completely separate. Olympic values = Excellence, Friendship, Respect (three values). Paralympic values = Courage, Determination, Inspiration, Equality (four values). If your answer swaps a value between the two lists, it loses the mark even if the value itself is spelled correctly.</p>", "question": "Which of these correctly sorts a value into its own movement?", "options": ["Courage is officially counted as one of the three Olympic values", "Respect is officially counted as one of the four Paralympic values", "Determination is one of the four Paralympic values", "Friendship is officially counted as one of the four Paralympic values"]}'::jsonb, '{"answer": 2, "explain": "Determination is genuinely one of the four Paralympic values. The other options wrongly place a value in the opposite movement''s list."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:misc:33325ce1', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students sometimes think ''Equality'' as a Paralympic value only means para-athletes should be treated the same as everyone else once the Games are already over.</p><p><strong>✅ The correct idea:</strong> Equality is broader than that. It is about every competitor being given the same fair opportunity to take part and to be recognised as an athlete in the first place — before, during and after competition — whatever their impairment, not just a rule about treatment after the event has finished.</p>", "question": "What does ''Equality'' as a Paralympic value actually cover?", "options": ["Only how athletes are treated once the Olympic and Paralympic Games have already finished", "Fair opportunity to take part and be recognised as an athlete, at every stage", "Making sure that every single athlete wins exactly the same number of medals", "Only which particular sports are included in the Paralympic programme itself"]}'::jsonb, '{"answer": 1, "explain": "Equality covers fair opportunity and recognition throughout, not only post-event treatment, medal counts, or the sports programme."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tips:7d73789c', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Questions on the Creed, the symbol and the values are usually short and precise. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two Olympic values [2]\" = two correct names, nothing more.</li>\n<li><strong>Describe</strong> — say what it is or what it involves. \"Describe the Olympic symbol [2]\" = the rings, interlocking, representing the continents.</li>\n<li><strong>Explain</strong> — give a reason, using the word <em>because</em>. \"Explain how an athlete showed Determination\" = name the value <em>and</em> link it to what they actually did.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point plus a short reason; higher tariffs in Section B/C want the value applied to the scenario, not just named.</p>", "question": "A question says: ''Identify two Paralympic values [2]''. What is the safest answer?", "options": ["A long paragraph describing one value in detail", "Two correct Paralympic value names", "One value name plus a lengthy explanation", "A list of all seven Olympic and Paralympic values"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two correct names, one mark each. A long paragraph on one value, or a list of every value, wastes time for no extra credit."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tips:66f926a7', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tips', 'mcq', 1, '{"readingTitle": "tip — Don''t muddle Olympic and Paralympic values", "reading": "<p>The single most common way to lose marks on this topic is placing a value in the wrong list. Learn them as two separate groups, and check every answer against the count:</p>\n<ul>\n<li><strong>Olympic values (three):</strong> Excellence, Friendship, Respect.</li>\n<li><strong>Paralympic values (four):</strong> Courage, Determination, Inspiration, Equality.</li>\n</ul>\n<p>If an answer names four \"Olympic values\" or three \"Paralympic values\", the count itself tells you a value has been placed in the wrong list before you even check which one.</p>", "question": "A student writes that the Olympic values are ''Excellence, Friendship, Respect and Courage'' — four values. What is the quickest way to spot the error?", "options": ["There is absolutely nothing wrong with including a fourth, different value in that same list of values itself", "The Olympic values are only three, so a fourth name means one has been borrowed from the Paralympic list", "Courage should simply replace Excellence as the third value in that same list", "The order that the four values happen to be written in is what is incorrect"]}'::jsonb, '{"answer": 1, "explain": "The Olympic values are exactly three (Excellence, Friendship, Respect). A fourth name — Courage — signals a Paralympic value has been mixed in by mistake."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:tips:0c7f5f12', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> the Creed, the symbol and the two value lists appear as quick recall in <strong>Section A</strong> (identify/state/describe), and as applied points in <strong>Section B</strong> scenarios about a sporting event or a performer''s behaviour. They can also feed a longer discussion of how sport promotes positive attitudes.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the two lists by their <em>count</em> first — three Olympic, four Paralympic — then the names.</li>\n<li>Never name a value alone; always link it to a behaviour (\"Determination, because the athlete kept training despite the injury\").</li>\n<li>Keep the Creed and the values separate in your head — the Creed is about effort vs. result, the values are named qualities.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One value shown here is… because…\"</li>\n<li>\"This matters because it links to the idea that…\"</li>\n<li>\"However, this value alone does not guarantee… because…\"</li>\n</ul>", "question": "Why is it important to link a named value to a specific behaviour in a scenario answer?", "options": ["It simply fills space and takes up extra time in the answer", "It shows understanding of what the value actually means, not just its name", "It completely replaces any need to name the value at all in the answer", "It guarantees full marks automatically, regardless of the accuracy given each time"]}'::jsonb, '{"answer": 1, "explain": "Naming a value alone shows recall; linking it to a behaviour in the scenario shows the understanding that scenario-based marks actually reward."}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:fib:bbb251c2', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'fib', 'fib', 1, '{"question": "The Olympic symbol is made up of five interlocking _____.", "blankOptions": {"B1": ["up", "Respect", "Equality", "rings"]}}'::jsonb, '{"blanks": {"B1": "rings"}}'::jsonb),
