('sport-studies:2-2-the-olympic-paralympic-movement:match:41f28184', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Olympic Creed”?", "options": ["An Olympic value about fair play and consideration for rules, opponents and yourself", "A statement of the philosophy behind the Games — that honest, maximum effort in competing matters as much as the result", "An Olympic value about the bonds and understanding that competing together can build across cultures", "An Olympic value about striving to reach your own personal best, not only about beating other people"]}'::jsonb, '{"answer": 1, "explain": "“Olympic Creed” means: A statement of the philosophy behind the Games — that honest, maximum effort in competing matters as much as the result"}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:match:b1c74b32', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Olympic symbol (five rings)”?", "options": ["Five interlocking rings representing the coming together of the five continents of the world through sport", "A Paralympic value about refusing to give up despite setbacks, and pushing on toward a goal", "An Olympic value about fair play and consideration for rules, opponents and yourself", "An Olympic value about the bonds and understanding that competing together can build across cultures"]}'::jsonb, '{"answer": 0, "explain": "“Olympic symbol (five rings)” means: Five interlocking rings representing the coming together of the five continents of the world through sport"}'::jsonb),
