('sport-studies:2-2-the-olympic-paralympic-movement:match:9fd1a08d', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Courage”?", "options": ["A Paralympic value about refusing to give up despite setbacks, and pushing on toward a goal", "A Paralympic value about the mental strength needed to face and overcome a real challenge", "An Olympic value about the bonds and understanding that competing together can build across cultures", "An Olympic value about fair play and consideration for rules, opponents and yourself"]}'::jsonb, '{"answer": 1, "explain": "“Courage” means: A Paralympic value about the mental strength needed to face and overcome a real challenge"}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:match:a18b817a', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Determination”?", "options": ["Five interlocking rings representing the coming together of the five continents of the world through sport", "A Paralympic value about refusing to give up despite setbacks, and pushing on toward a goal", "A Paralympic value about the mental strength needed to face and overcome a real challenge", "A Paralympic value about using a performance to motivate people and change how they think"]}'::jsonb, '{"answer": 1, "explain": "“Determination” means: A Paralympic value about refusing to give up despite setbacks, and pushing on toward a goal"}'::jsonb),
('sport-studies:2-2-the-olympic-paralympic-movement:match:f5f51fdd', 'sport-studies', 'sport-studies:2-2-the-olympic-paralympic-movement', '2.2 The Olympic & Paralympic Movement', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Inspiration”?", "options": ["An Olympic value about the bonds and understanding that competing together can build across cultures", "A Paralympic value about using a performance to motivate people and change how they think", "A Paralympic value about the mental strength needed to face and overcome a real challenge", "An Olympic value about striving to reach your own personal best, not only about beating other people"]}'::jsonb, '{"answer": 1, "explain": "“Inspiration” means: A Paralympic value about using a performance to motivate people and change how they think"}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:exam:14f5522c', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these best describes a sporting ''campaign''?", "options": ["A single trophy presented once a year to the most successful full-time professional team in the country", "An organised effort with a message, run over time, to raise awareness or change attitudes", "A permanent change to the official written rules of a sport", "A one-off friendly match with no promotional message attached"], "hint": "Think about what runs over TIME and carries a MESSAGE.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — An organised effort with a message, run over time, to raise awareness or change attitudes.</strong></p>\n<ul>\n<li>A campaign runs over a period and carries a clear message.</li>\n<li>A trophy, a rule change, or a plain friendly match are not campaigns.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:mcq:05b388f0', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'mcq', 'mcq', 1, '{"question": "Which of these is the best definition of an ''initiative'' in sport?", "options": ["A single, one-off training session that is only ever open to elite, full-time professional performers", "A permanent change to the official laws of how a sport is refereed", "A planned scheme, set up by an organisation, that works towards a participation or values goal", "A private club social evening with no wider promotional aim"]}'::jsonb, '{"answer": 2, "explain": "An initiative is a planned scheme working towards a goal, such as more people taking part. A one-off elite session, a law change, or a private social evening are not initiatives."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:mcq:58172e49', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'mcq', 'mcq', 1, '{"question": "A sporting campaign is best described as...", "options": ["An organised effort with a message, run over time, to raise awareness or change attitudes", "A single trophy presented once a year to the most successful full-time professional team in the country", "A new law passed by a national government that has nothing to do with sport", "A one-off friendly match with no promotional message attached to it at all"]}'::jsonb, '{"answer": 0, "explain": "A campaign is an organised effort with a message, run over time. A trophy, a law, or a plain friendly match are not campaigns."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:mcq:4534df7a', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'mcq', 'mcq', 1, '{"question": "A national governing body runs a scheme across the whole country, timed around a major tournament, encouraging respect for officials. This is operating at which level?", "options": ["Local, because the idea was first suggested by one grassroots club committee", "Regional", "International, because it copies an idea used somewhere else in the world", "National"]}'::jsonb, '{"answer": 3, "explain": "A scheme run by a governing body across the whole country is national — bigger than one club (local) or one area (regional)."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:mcq:9aa7988f', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'mcq', 'mcq', 1, '{"question": "A local club''s open day pairs every new member with an experienced player for their first session, whatever their ability. This mainly promotes...", "options": ["Excellence, because it is designed to identify future full-time professional performers", "National pride", "Citizenship, and nothing about welcoming new members at all", "Inclusion"]}'::jsonb, '{"answer": 3, "explain": "Welcoming and supporting newcomers of any ability is inclusion. It is not about spotting elite talent, national pride, or citizenship."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:mcq:196c8040', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'mcq', 'mcq', 1, '{"question": "Which of these best shows a campaign ''raising awareness'', rather than ''encouraging take-up''?", "options": ["A free, six-week taster course that is fully funded and open to any new participant who wants to join", "A television and social media advert explaining why respecting match officials matters", "A discounted membership price offered only during the very first month of joining", "A qualified buddy assigned to every single beginner who attends a session"]}'::jsonb, '{"answer": 1, "explain": "An advert that explains why a value matters raises awareness. Taster courses, discounted prices and buddies are all ways of encouraging take-up instead."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:mcq:bf213d2c', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'mcq', 'mcq', 1, '{"question": "A regional schools'' festival gives its award to the side that supports its opponents best after losing, not only to the winners. Which values does this mainly promote?", "options": ["Excellence only, because just the single best-performing team can ever win it", "National pride, and nothing connected to how teams treat each other", "Tolerance and respect only, with no connection to teamwork", "Fair play and team spirit"]}'::jsonb, '{"answer": 3, "explain": "Rewarding good conduct towards opponents, win or lose, promotes fair play and team spirit — not simply rewarding the best performance or national pride."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tf:f8271c83', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tf', 'tf', 1, '{"question": "An initiative is a planned scheme set up by an organisation to work towards a goal."}'::jsonb, '{"answer": true, "explain": "That''s the definition — a planned scheme aimed at something like increasing participation or promoting a value."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tf:c297562b', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tf', 'tf', 1, '{"question": "A campaign and an event are exactly the same thing."}'::jsonb, '{"answer": false, "explain": "A campaign is an organised effort with a message, run over time. An event is one staged occasion. An initiative can include both."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tf:7c049f7c', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tf', 'tf', 1, '{"question": "Initiatives, campaigns and events can only ever operate at national level."}'::jsonb, '{"answer": false, "explain": "They can operate at local, regional or national level — a single club''s open day is just as valid an example as a nationwide campaign."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tf:bef6a162', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tf', 'tf', 1, '{"question": "Raising awareness and encouraging take-up are the same single step."}'::jsonb, '{"answer": false, "explain": "Raising awareness gets people to notice a value or issue. Encouraging take-up turns that awareness into people actually starting. They are two separate jobs."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tf:a24dd1d1', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tf', 'tf', 1, '{"question": "A local club open day that welcomes new members of any ability can promote inclusion."}'::jsonb, '{"answer": true, "explain": "Yes — welcoming and supporting newcomers regardless of ability is a clear, everyday example of promoting inclusion at local level."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tf:bc786889', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tf', 'tf', 1, '{"question": "The level an initiative runs at (local, regional or national) decides which value it is allowed to promote."}'::jsonb, '{"answer": false, "explain": "Any value can be promoted at any level. The level is about the size of the audience and who organises it, not which value is allowed."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:learn:a0e834f6', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'learn', 'mcq', 1, '{"readingTitle": "What is an initiative, campaign or event?", "reading": "<h4>Three different tools, one job</h4>\n<ul>\n<li>An <strong>initiative</strong> is a planned scheme, set up by an organisation, that works towards a goal — such as getting more people from a particular group taking part in sport.</li>\n<li>A <strong>campaign</strong> is an organised effort, usually with a clear message, that runs over a period of time to raise awareness of an issue or change attitudes — for example, encouraging more respectful behaviour towards officials.</li>\n<li>An <strong>event</strong> is a specific, staged occasion — a festival, a tournament, an open day — that brings people together on the day itself to promote a value or attract new participants.</li>\n<li>All three exist to promote one or more of the <strong>sporting values</strong> from 2.1: team spirit, fair play, citizenship, tolerance and respect, inclusion, national pride and excellence.</li>\n</ul>\n<h4>Why organisations bother</h4>\n<ul>\n<li>Initiatives, campaigns and events give sport a way to <strong>put a value into action</strong>, rather than just naming it. A club can say it values inclusion, but an open day for newcomers of any ability actually demonstrates it.</li>\n<li>The exam rarely tests whether you can just name one — it tests whether you can say <strong>which value</strong> it promotes and <strong>how</strong> it does that.</li>\n</ul>", "question": "Which of these best describes a ''campaign''?", "options": ["An organised effort with a clear message, run over time to raise awareness or change attitudes", "A single one-off training session that only professional, full-time athletes are permitted to attend", "A permanent change to the official written rules of how a sport is played", "A private members-only social event with no wider promotional purpose"]}'::jsonb, '{"answer": 0, "explain": "A campaign is an organised effort with a message that runs over time. A one-off elite session, a rule change, or a private social event are not campaigns."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:learn:8624b087', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'learn', 'mcq', 1, '{"readingTitle": "Local, regional and national — same values, different reach", "reading": "<h4>Three levels of reach</h4>\n<ul>\n<li><strong>Local</strong> — run by one club, school or leisure centre for its own community. Example: a local football club holds an open day where new players of any ability are paired with an experienced member for their first session, promoting <strong>inclusion</strong>.</li>\n<li><strong>Regional</strong> — run across a county or area, often by several clubs or a regional partnership working together. Example: a regional schools'' festival gives an award to the side that supports its opponents best after a defeat, not only to the winners, promoting <strong>fair play</strong> and <strong>team spirit</strong>.</li>\n<li><strong>National</strong> — run by a national governing body, or across the whole country, often timed around a major competition. Example: a national campaign asks players and spectators at every level of the game to show more respect towards match officials, promoting <strong>tolerance and respect</strong>.</li>\n</ul>\n<h4>The level does not decide the value</h4>\n<ul>\n<li>Any value can be promoted at any level — a local club can promote national pride just as easily as a national campaign can promote inclusion.</li>\n<li>What changes between the levels is <strong>the size of the audience and who organises it</strong>, not the value itself.</li>\n</ul>", "question": "A scheme run across one county by several schools working together, encouraging good sporting conduct, is operating at which level?", "options": ["Local, because it only ever involves students from a single school site", "Regional", "National, because a governing body must personally organise every single entry", "International, because it copies an idea first used in another country"]}'::jsonb, '{"answer": 1, "explain": "Several schools working together across a county is a regional scheme — bigger than one club or school, smaller than a nationwide one."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:learn:43129371', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'learn', 'mcq', 1, '{"readingTitle": "Awareness and take-up — how initiatives actually change behaviour", "reading": "<h4>Two jobs, in order</h4>\n<ul>\n<li><strong>Raising awareness</strong> comes first — getting people to notice and think about a value or issue, often through publicity, a launch event or media coverage.</li>\n<li><strong>Encouraging take-up</strong> comes next — turning that awareness into action, by making it easy for new or lapsed participants to actually start (free taster sessions, discounted membership, a buddy to go with).</li>\n<li>A strong initiative usually does both: for example, a national campaign about inclusion might use adverts to raise awareness, while local clubs run free taster sessions in the same week so people who noticed the campaign can immediately try something.</li>\n</ul>\n<h4>Building an exam answer</h4>\n<ul>\n<li>Weak answer: <em>\"There is a campaign about respect.\"</em> — names something but shows no understanding.</li>\n<li>Strong answer: <em>\"A national campaign encourages respect for match officials by asking players and fans to applaud decisions rather than argue with them. This raises awareness of the value of respect and, alongside training for new referees, encourages more people to take up officiating.\"</em></li>\n<li>The mark almost always comes from linking the initiative to the <strong>value</strong> it promotes, the <strong>level</strong> it operates at, and <strong>how</strong> it raises awareness or encourages take-up.</li>\n</ul>", "question": "An initiative gives out free taster sessions straight after a media campaign about a value. The taster sessions are mainly intended to...", "options": ["guarantee that every single attendee eventually becomes a full-time professional performer", "encourage take-up by making it easy for people to actually start", "replace the campaign''s job of raising any awareness at all", "reduce the total number of people who are allowed to try the sport"]}'::jsonb, '{"answer": 1, "explain": "Taster sessions turn awareness into action — they encourage take-up. They do not guarantee professional careers, replace the awareness stage, or limit numbers."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:misc:caef999a', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> As long as I can name an initiative or campaign, I''ll get the marks.</p><p><strong>✅ The correct idea:</strong> Naming is only the first mark at most. The examiner wants you to link the initiative to the VALUE it promotes, the LEVEL it operates at, and HOW it raises awareness or encourages take-up. Weak answer: \"There is a campaign about respect.\" Strong answer: \"A national campaign encourages respect for officials by asking fans to applaud decisions rather than argue, raising awareness of respect and encouraging more people to take up officiating.\"</p>", "question": "A question asks you to explain how an initiative promotes a sporting value. What earns the marks?", "options": ["Naming as many different initiatives as you can remember", "Writing the initiative''s name in capital letters for emphasis", "Naming the initiative, its value, and how it works", "Describing a sporting event you personally attended"]}'::jsonb, '{"answer": 2, "explain": "Explain = name it, then the value it promotes, then how it works. Naming alone, or listing several, does not show that understanding."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:misc:51a308e0', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A campaign and an event are the same thing — anything promoting sport counts as both.</p><p><strong>✅ The correct idea:</strong> They are related but different. An EVENT is one staged occasion on a specific day, like a festival or open day. A CAMPAIGN is an organised effort with a message that runs over a longer period, often using adverts or media. An initiative can use an event as part of a wider campaign, but the words are not interchangeable.</p>", "question": "Which of these is an example of an event, rather than a campaign?", "options": ["A six-month advertising effort encouraging respect for officials", "A one-day regional schools'' sports festival", "A national media message repeated across an entire year", "A rolling programme of adverts about inclusion shown all season"]}'::jsonb, '{"answer": 1, "explain": "A one-day festival is a staged occasion — an event. The others run over a longer period with a message, which makes them campaigns."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:misc:d424bb10', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Raising awareness'' and ''encouraging take-up'' mean the same thing.</p><p><strong>✅ The correct idea:</strong> They are two separate jobs that often work together. RAISING AWARENESS means getting people to notice and think about a value or issue, often through adverts or media. ENCOURAGING TAKE-UP means making it easy for people to actually start or return, for example through free taster sessions. A campaign can raise awareness without a single new participant turning up unless take-up is also encouraged.</p>", "question": "A national advert explains why fair play matters, but no local sessions are ever offered afterwards. This campaign has...", "options": ["encouraged take-up through free local sessions but not really raised any awareness", "raised awareness but done little to encourage take-up", "done neither job at all, despite the advert being shown nationally", "done exactly the same job twice over, both raising awareness and encouraging take-up"]}'::jsonb, '{"answer": 1, "explain": "An advert alone raises awareness. Without taster sessions, discounts or another route in, it has done little to encourage take-up."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:misc:1686931d', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Only national campaigns count for this topic — a local club''s small open day doesn''t really count as an ''initiative''.</p><p><strong>✅ The correct idea:</strong> A local scheme is just as valid an example as a national one. The specification expects you to recognise initiatives, campaigns and events at LOCAL, REGIONAL and NATIONAL level. A local club open day that welcomes new members is a perfectly good example — you just need to say which level it operates at and which value it promotes.</p>", "question": "Which of these could be used as a valid exam example of an initiative promoting a sporting value?", "options": ["Only a scheme that has been personally organised by a national governing body itself", "A local club''s open day for new members of any ability", "Only a scheme that has been shown at some point on national television", "Only a scheme that is directly linked to an international competition"]}'::jsonb, '{"answer": 1, "explain": "Local examples are just as valid as national ones — you simply need to identify the correct level and the value it promotes."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tips:a386e774', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Initiative and campaign questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two levels at which an initiative can operate\" = write two levels, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what the initiative looks like or does. \"Describe an initiative that promotes inclusion\" = give its features.</li>\n<li><strong>Explain</strong> — give a reason or a mechanism. Use the word <em>because</em> or <em>by</em>. \"Explain how a campaign encourages take-up\" = what it does, and how that leads to people starting.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed; [4] in Section B wants points applied to the scenario.</p>", "question": "A question says: ''Identify two levels at which an initiative can operate [2]''. What is the safest answer?", "options": ["A long paragraph describing one national campaign in detail", "Two level names, such as local and national", "One level explained at great length", "A list of every value from 2.1"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. A long paragraph, or an unrelated list of values, wastes time and does not answer the question."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tips:f6fc0f3e', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: value, level, and how", "reading": "<p>The single most common way to lose marks here is naming an initiative with nothing else. Build every answer as <strong>initiative → value → level → how it works</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"There is a campaign about respect.\"</li>\n<li><strong>✅ full marks:</strong> \"A national campaign promotes respect by asking fans to applaud officials'' decisions rather than argue, raising awareness of the value and encouraging more people to take up officiating.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named club or trust). Then you must use a detail <em>from that scenario</em>, not a general example.</p>", "question": "In a Section B scenario question about a named sports trust, your example should be built around...", "options": ["absolutely any campaign you happen to have seen on television", "the scenario you are given", "a famous athlete you personally admire", "your own school''s sports day only"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general example that ignores the scenario is capped."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:tips:5622cb86', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> initiatives and campaigns appear as quick recall in <strong>Section A</strong> (identify a level, identify a value), and as applied points in <strong>Section B</strong> scenarios about a named club or trust. They also feed <strong>Section C</strong> 8-mark answers about how a range of initiatives could work together to promote values.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn one clear example at each level (local, regional, national) so you can always recall one.</li>\n<li>For every example, memorise the value it promotes AND how it raises awareness or encourages take-up.</li>\n<li>Watch for overlap: one initiative can promote more than one value, and can raise awareness while also encouraging take-up.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One initiative that promotes this value is… run at… level, which works by…\"</li>\n<li>\"This raises awareness by… and encourages take-up by…\"</li>\n<li>\"However, the same initiative might not reach… because…\"</li>\n</ul>", "question": "Why is it useful to know that one initiative can raise awareness AND encourage take-up?", "options": ["It simply fills space in a longer answer without adding any real understanding", "It shows understanding of both jobs an initiative can do", "It means the initiative has no value attached to it whatsoever", "It completely replaces the need to ever name a level or a value"]}'::jsonb, '{"answer": 1, "explain": "Showing that an initiative does both jobs — raising awareness and encouraging take-up — demonstrates the deeper understanding a longer answer rewards."}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:fib:09142a88', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'fib', 'fib', 1, '{"question": "An _____ is a planned scheme set up by an organisation to work towards a goal.", "blankOptions": {"B1": ["initiative", "national", "take", "time"]}}'::jsonb, '{"blanks": {"B1": "initiative"}}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:fib:f03b6a47', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'fib', 'fib', 1, '{"question": "A campaign is an organised effort with a message, run over _____, to change attitudes.", "blankOptions": {"B1": ["staged", "take", "time", "local"]}}'::jsonb, '{"blanks": {"B1": "time"}}'::jsonb),
('sport-studies:2-3-initiatives-and-campaigns:fib:6e30f8c0', 'sport-studies', 'sport-studies:2-3-initiatives-and-campaigns', '2.3 Initiatives and Campaigns', 'fib', 'fib', 1, '{"question": "An event is a specific, _____ occasion, such as a festival or open day.", "blankOptions": {"B1": ["take", "time", "staged", "national"]}}'::jsonb, '{"blanks": {"B1": "staged"}}'::jsonb),
