('sport-studies:2-4-1-etiquette-of-performers:exam:377abe24', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these best describes gamesmanship?", "options": ["Deliberately and very openly breaking one of the sport''s official written rules right in front of the referee", "Bending the rules or chasing a legal-but-unfair edge, without technically breaking a written rule", "Respecting both the written rules and their fair-play spirit at every single moment", "Refusing to take part in a contest unless conditions are perfect"], "hint": "Think about whether a written rule is actually broken or not.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Bending the rules or chasing a legal-but-unfair edge, without technically breaking a written rule.</strong></p>\n<ul>\n<li>Gamesmanship always stays inside the written rulebook while seeking an advantage.</li>\n<li>Openly breaking a rule is cheating, and respecting the letter AND spirit of the rules describes sportsmanship instead.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:mcq:0c0f7a77', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'mcq', 'mcq', 1, '{"question": "Which of these is a genuine reason performers are expected to observe etiquette?", "options": ["It reinforces positive sporting values and protects fairness and safety", "It guarantees that the more experienced performer will always win the contest", "It replaces the need for a referee or official to be present at the match", "It only applies to professional performers, never to school or club sport"]}'::jsonb, '{"answer": 0, "explain": "Etiquette exists for fairness, safety and reinforcing values — it never guarantees a result, replaces officials, or applies only to professionals."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:mcq:f7564da7', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'mcq', 'mcq', 1, '{"question": "A golfer''s playing partner is standing over the ball, about to take a decisive putt. What should the golfer do?", "options": ["Quietly shuffle their feet and check their phone to pass the time", "Stay completely still and silent until the putt has been taken", "Walk onto the green to check where the flag is", "Ask the playing partner to hurry up and take the putt"]}'::jsonb, '{"answer": 1, "explain": "Etiquette means holding back completely during a decisive shot. Shuffling, walking onto the green, or rushing the other player would all distract or disrupt."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:mcq:918c49f7', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'mcq', 'mcq', 1, '{"question": "Which sentence best shows sportsmanship rather than gamesmanship?", "options": ["A player stays carefully inside every written rule while quietly searching out every possible legal advantage they can find", "A player argues with the referee until the decision is changed in their favour", "A player admits fouling even though the referee doesn''t spot it, and accepts the decision going against them", "A player refuses to shake hands with the opposition after losing a close match"]}'::jsonb, '{"answer": 2, "explain": "Owning up when nobody is checking shows respect for the spirit of the rules — true sportsmanship. Option A instead describes chasing legal advantages, which is gamesmanship."}'::jsonb)
